for rec in records:
    function_ids = rec.x_baseline_functional_area_id.x_function_ids.ids if rec.x_baseline_functional_area_id else []
    rec.sudo().write({'x_baseline_function_ids': [(6, 0, function_ids)]})

for rec in records:
    if not rec.job_id or rec.x_role_and_duty_line_ids:
        continue

    line_commands = []
    for sequence, function in enumerate(rec.job_id.x_baseline_function_ids, start=1):
        function_area = function.x_functional_area_id or rec.job_id.x_baseline_functional_area_id
        if not function_area:
            continue

        line_commands.append((0, 0, {
            'x_name': function.display_name,
            'x_sequence': sequence * 10,
            'x_functional_area_id': function_area.id,
            'x_function_id': function.id,
        }))

    if line_commands:
        rec.sudo().write({'x_role_and_duty_line_ids': line_commands})
